insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('economics:4-2-balance-of-payments:mcq:208e0bfc', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'mcq', 'mcq', 1, '{"question": "How does supply side policy improve a country''s balance of payments?", "options": ["By leading to a higher rate of inflation", "By raising consumption by domestic consumers", "By cancelling free trade agreements", "By improving the productivity of the labour force"]}'::jsonb, '{"answer": 3, "explain": "Higher productivity lowers costs per unit, so exports become more internationally competitive. Higher inflation and higher consumption would both WORSEN the balance of payments."}'::jsonb),
('economics:4-2-balance-of-payments:mcq:0cf348bc', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'mcq', 'mcq', 1, '{"question": "A rise in the UK''s exchange rate would most likely...", "options": ["Improve the current account, as exports become cheaper", "Worsen the current account, as exports become dearer and imports cheaper", "Improve the current account, as imports become dearer", "Have no effect on the current account"]}'::jsonb, '{"answer": 1, "explain": "A stronger pound makes UK exports more expensive abroad (demand falls) and imports cheaper at home (demand rises) — both push the current account towards deficit."}'::jsonb),
('economics:4-2-balance-of-payments:tf:6e376c6c', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'tf', 'tf', 1, '{"question": "The balance of payments is the same thing as the government''s budget."}'::jsonb, '{"answer": false, "explain": "This is the single most-reported misconception on this topic. The balance of payments records a COUNTRY''S transactions with the rest of the world; the government budget is tax and spending. Examiners repeatedly saw candidates write about raising taxes to ''pay for'' a trade deficit — that scores nothing."}'::jsonb),
('economics:4-2-balance-of-payments:tf:aa7e728f', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'tf', 'tf', 1, '{"question": "A Spanish firm buying land in the UK to build a factory is recorded in the UK''s current account."}'::jsonb, '{"answer": false, "explain": "That is investment, so it belongs in the FINANCIAL account. The current account covers trade in goods, trade in services, income flows and transfers."}'::jsonb),
('economics:4-2-balance-of-payments:tf:4b700f9a', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'tf', 'tf', 1, '{"question": "The balance of trade is only part of the current account."}'::jsonb, '{"answer": true, "explain": "The balance of trade covers goods and services only. It is the largest component, but the current account also includes income flows and transfers."}'::jsonb),
('economics:4-2-balance-of-payments:tf:0fd8f7ea', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'tf', 'tf', 1, '{"question": "The UK typically runs a surplus on trade in goods and a deficit on trade in services."}'::jsonb, '{"answer": false, "explain": "It is the other way round. The UK runs a large DEFICIT on goods and a SURPLUS on services — which is why the goods-only deficit is always bigger than the goods-and-services deficit."}'::jsonb),
('economics:4-2-balance-of-payments:tf:0da7a7c8', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'tf', 'tf', 1, '{"question": "A current account deficit is automatically bad for an economy."}'::jsonb, '{"answer": false, "explain": "It depends on the cause, the size relative to GDP and the duration. A deficit financed by inward investment that brings new technology, and which stays small as a share of GDP, is very different from one caused by collapsing demand for domestic goods."}'::jsonb),
('economics:4-2-balance-of-payments:tf:a83328e9', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'tf', 'tf', 1, '{"question": "A country''s currency tends to weaken when it runs a current account deficit."}'::jsonb, '{"answer": true, "explain": "More of the currency is sold to buy imports and less is bought to purchase its exports, so supply rises and demand falls — pushing the exchange rate down. That lower rate should then make exports more competitive."}'::jsonb),
('economics:4-2-balance-of-payments:tf:23cece17', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'tf', 'tf', 1, '{"question": "If a country''s inflation rate falls below its trading partners'', its exports become less competitive."}'::jsonb, '{"answer": false, "explain": "Lower relative inflation makes exports MORE competitive, because your prices are rising more slowly than rivals''. It is HIGHER inflation than your trading partners that damages competitiveness."}'::jsonb),
('economics:4-2-balance-of-payments:tf:617e34f4', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'tf', 'tf', 1, '{"question": "A deficit of £2m in a country with £40m GDP is more serious than a deficit of £4m in a country with £100m GDP."}'::jsonb, '{"answer": true, "explain": "Judge deficits relative to GDP: 2/40 = 5% versus 4/100 = 4%. The smaller cash deficit is the bigger burden — which is exactly why the UK''s persistent deficit is still judged manageable."}'::jsonb),
('economics:4-2-balance-of-payments:learn:45636189', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'learn', 'mcq', 1, '{"readingTitle": "The balance of payments and the current account", "reading": "<p><strong>The balance of payments is a record of all the financial transactions between a country and the rest of the world over a period of time.</strong> The exam only requires detail on the <strong>current account</strong>.</p>\n<h4>The three parts of the balance of payments</h4>\n<ul>\n<li><strong>Current account</strong> — trade plus income plus transfers. This is the GCSE focus.</li>\n<li><strong>Capital account</strong> — international capital transfers.</li>\n<li><strong>Financial account</strong> — investment flows in and out (buying businesses, property, shares, bonds).</li>\n</ul>\n<p>Careful: a <strong>Spanish firm buying land in the UK to build a factory</strong> is investment — it goes in the FINANCIAL account, NOT the current account. This is a real MCQ.</p>\n<h4>The four components of the current account</h4>\n<ul>\n<li><strong>Trade in goods</strong> — exports minus imports of physical (\"visible\") goods, e.g. cars, laptops, food.</li>\n<li><strong>Trade in services</strong> — exports minus imports of services, e.g. tourism, finance, insurance, education.</li>\n<li><strong>Income flows</strong> — income UK residents earn on investments abroad, minus income foreign nationals earn on their investments in the UK.</li>\n<li><strong>Transfers</strong> — money sent abroad with nothing received in return, e.g. foreign aid, or migrant workers sending money home.</li>\n</ul>\n<h4>The balance of trade</h4>\n<ul>\n<li>The <strong>balance of trade</strong> is just the record of trade in goods and services — the first TWO components. It is the largest part of the current account, but it is NOT the whole current account.</li>\n<li>The whole current account = trade in goods + trade in services + income flows + transfers.</li>\n</ul>\n<h4>The UK''s pattern — learn this, it is the case study</h4>\n<ul>\n<li>The UK runs a <strong>large deficit on trade in goods</strong> but a <strong>surplus on trade in services</strong>.</li>\n<li>The UK has run an annual current account <strong>deficit since 1983</strong>.</li>\n<li>Services the UK exports: tourism, financial services/banking, insurance, education (overseas student fees), IT, transport.</li>\n</ul>", "question": "Which of these is NOT part of the UK''s current account?", "options": ["A Spanish firm buying land in the UK to build a factory", "A UK consumer spending money on holiday in Greece", "Interest earned by a UK person from a bank account in France", "Foreign aid sent from the UK to a less developed country"]}'::jsonb, '{"answer": 0, "explain": "Buying land to build a factory is INVESTMENT, so it sits in the financial account. Aid is a transfer, holiday spending is an import of services, and interest from abroad is an income flow — all three are current account items."}'::jsonb),
('economics:4-2-balance-of-payments:learn:b7ce832a', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'learn', 'mcq', 1, '{"readingTitle": "Balanced, surplus, deficit — and how to calculate them", "reading": "<p>Add up the net figure for each of the four components, then sum them.</p>\n<ul>\n<li><strong>Balanced current account:</strong> the four components net to zero — money in equals money out.</li>\n<li><strong>Surplus:</strong> the sum of exports of goods, services, investment income and transfers is <strong>GREATER than</strong> imports. More money flows in than out.</li>\n<li><strong>Deficit:</strong> that sum is <strong>LESS than</strong> imports. More money flows out than in.</li>\n</ul>\n<h4>The precise definition of a surplus</h4>\n<p>The exam tests whether you know a surplus covers ALL FOUR components, not just trade. The \"best\" definition is: <strong>the sum of export revenue and the inflow of income and transfers exceeds the outflow on imports, income and transfers</strong>. A definition mentioning only goods and services is <em>almost</em> right — which is exactly why it is offered as a distractor.</p>\n<h4>Worked example — the four-component method</h4>\n<ul>\n<li>Goods: exports £200m − imports £350m = <strong>−£150m</strong></li>\n<li>Services: exports £400m − imports £100m = <strong>+£300m</strong></li>\n<li>Income flows: <strong>−£20m</strong>; Transfers: <strong>−£20m</strong></li>\n<li>Balance = −150 + 300 − 20 − 20 = <strong>+£110m surplus</strong></li>\n</ul>\n<h4>Where the marks actually go</h4>\n<ul>\n<li><strong>A deficit is NEGATIVE.</strong> Write the minus sign, or the word \"deficit\". Miss it and you drop a mark.</li>\n<li><strong>Write the units.</strong> \"£ million\" or \"m\". The examiners repeatedly report candidates losing a mark for omitting the £ sign or \"million\".</li>\n<li><strong>Deficit as a % of GDP</strong> = deficit ÷ GDP × 100. A £10bn deficit with £200bn national output = <strong>5%</strong>. This is how you judge whether a deficit is actually serious.</li>\n<li><strong>Percentage change</strong> = change ÷ original × 100. A deficit growing from £30 000m to £80 000m = 50 000/30 000 × 100 = <strong>166.67%</strong>.</li>\n</ul>", "question": "A country has a current account deficit of £10 billion and national output of £200 billion. The deficit as a percentage of national output is...", "options": ["50%", "20%", "5%", "10%"]}'::jsonb, '{"answer": 2, "explain": "Deficit ÷ GDP × 100 = 10/200 × 100 = 5%. Expressing the deficit as a share of GDP is how you judge whether it is actually a serious problem."}'::jsonb),
('economics:4-2-balance-of-payments:learn:84c7c9ad', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'learn', 'mcq', 1, '{"readingTitle": "The causes of deficits and surpluses", "reading": "<p>The causes of surpluses and deficits are essentially <strong>mirror images</strong>. Learn the four factors once, then apply each in whichever direction the question needs.</p>\n<h4>Causes of a SURPLUS</h4>\n<ul>\n<li><strong>Reputation</strong> — a strong record builds a reputation for quality, in-demand goods and services. The UK is strong in financial services, medical research, aerospace and education.</li>\n<li><strong>A weak domestic economy</strong> — limited opportunities at home push firms to sell abroad, and lower incomes reduce demand for imports.</li>\n<li><strong>A falling exchange rate</strong> — makes exports cheaper abroad and imports dearer at home.</li>\n<li><strong>Investment inflows</strong> — more income flowing in from residents'' overseas investments than flows out.</li>\n</ul>\n<h4>Causes of a DEFICIT</h4>\n<ul>\n<li><strong>Poor reputation</strong> — being seen as overpriced or poor quality cuts export demand. Structural problems producing overpriced, poor-quality goods lead straight to a deficit.</li>\n<li><strong>Declining industries</strong> — relying on industries with falling demand destroys export potential. The UK''s manufacturing decline is the standard example.</li>\n<li><strong>A rising exchange rate</strong> — makes exports dearer and imports cheaper.</li>\n<li><strong>Falling incomes overseas</strong> — poorer customers abroad buy fewer of our exports.</li>\n<li><strong>Investment outflows</strong> — more income flowing out to foreign investors here than flows in. A <strong>net outflow of investment income</strong> directly worsens the current account.</li>\n<li><strong>Low productivity</strong> — raises costs per unit, making UK goods less internationally competitive. This is why supply side policy (which raises productivity) improves the balance of payments.</li>\n<li><strong>Rising domestic incomes</strong> — richer consumers suck in more imports.</li>\n</ul>\n<h4>Why the UK specifically</h4>\n<ul>\n<li>Since about 1990 the UK has developed resources more suited to exporting <strong>services</strong>, so fewer resources go into goods.</li>\n<li>Imports from highly competitive Asian economies grow faster than UK exports.</li>\n<li>Foreign investment in the UK is larger than UK investment abroad, so the <strong>income account is usually in deficit</strong> — foreign-owned assets here earn more than UK-owned assets abroad.</li>\n</ul>", "question": "Which of these would most likely help CREATE a balance of payments deficit on the UK current account?", "options": ["A net outflow of investment income", "A depreciation of the UK exchange rate", "An increase in the quality of UK output", "A fall in GDP per capita in the UK"]}'::jsonb, '{"answer": 0, "explain": "A net outflow of investment income is money leaving the current account, so it directly pushes it towards deficit. Better quality and a depreciation both boost exports; falling GDP per capita cuts import demand."}'::jsonb),
('economics:4-2-balance-of-payments:learn:7fc7b7e2', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'learn', 'mcq', 1, '{"readingTitle": "How important is the balance of payments?", "reading": "<p><strong>Never just say \"a deficit is bad\".</strong> The evaluation the examiners want is that the impact <strong>depends on the cause, the size relative to GDP, and whether it is short-term or persistent</strong>.</p>\n<h4>Why a deficit can matter</h4>\n<ul>\n<li><strong>Falling demand for domestic goods</strong> → firms need fewer workers → unemployment rises → the unemployed spend less → a <strong>negative cyclical spiral</strong>. This is the most serious cause.</li>\n<li><strong>Low productivity</strong> → slow to fix, because training and education take years to feed through.</li>\n<li><strong>Debt builds up</strong> — spending more on imports than is earned from exports means the country must borrow or sell assets. The UK is a <strong>net borrower</strong> and finances its deficit by attracting overseas investment.</li>\n<li><strong>Downward pressure on the exchange rate</strong> — more pounds sold to buy imports, fewer bought to buy our exports.</li>\n</ul>\n<h4>Why a deficit can be fine</h4>\n<ul>\n<li><strong>It is small relative to GDP</strong> — the single most important point for the UK. The deficit is persistent but has stayed a small percentage of GDP.</li>\n<li><strong>Lower inflation</strong> — cheap imports and less demand for domestic output ease demand-pull pressure.</li>\n<li><strong>Consumers gain</strong> — a wide variety of low-priced imports raises living standards. Global competition also means scarce resources are used more efficiently.</li>\n<li><strong>The inflow that finances it brings new technologies</strong> into the UK.</li>\n<li><strong>A lower exchange rate</strong> should make UK exports more competitive, which self-corrects some of the deficit.</li>\n</ul>\n<h4>A surplus — the same logic, reversed</h4>\n<ul>\n<li>Rising demand for domestic goods → firms hire → incomes rise → a <strong>positive spiral</strong>. Germany is the standard example.</li>\n<li>Export income more than covers imports, so <strong>debt falls</strong>.</li>\n<li>But: more demand for domestic output can create <strong>demand-pull inflation</strong>, and a <strong>stronger exchange rate</strong> eventually makes exports less competitive.</li>\n</ul>\n<p><strong>The judgement lever:</strong> a short one-off deficit after years of surplus matters far less than a persistent one — and the UK''s is persistent, but small as a share of GDP.</p>", "question": "Why is the UK''s persistent current account deficit judged less serious in practice?", "options": ["Because it has stayed a small percentage of GDP", "Because the UK never borrows from abroad", "Because it only lasted one year", "Because the UK has a surplus on trade in goods"]}'::jsonb, '{"answer": 0, "explain": "Size relative to GDP is what matters most. The UK''s deficit is persistent (since 1983) and so fails the ''duration'' test — but it has remained a small share of GDP, which is why it is judged manageable."}'::jsonb),
('economics:4-2-balance-of-payments:misc:87f4d4c8', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"The UK has a current account deficit, so the government needs to raise taxes to pay it off.\"</p><p><strong>✅ The correct idea:</strong> This is the examiners'' most-flagged misconception on the whole topic, and it appears in THREE separate mark schemes. On Q3(c) they wrote: \"A common misconception is confusion between the trade balance and government finances. Several candidates wrote about the need to increase taxation to pay for the deficit.\" On Q17(c): \"Most candidates identified reasons for a persistent current account deficit but confused this with a government budget deficit.\" And on Q16(d)(iii) they warn outright: \"Try not to confuse the balance of payments on the current account with fiscal policy and the balanced government budget.\" They are completely different things. The current account is the whole COUNTRY''S trading position with the rest of the world; the budget is the GOVERNMENT''S tax and spending. A current account deficit is financed by attracting financial inflows — selling assets to overseas investors or borrowing from the rest of the world — not by taxation.</p>", "question": "How is the UK''s current account deficit actually financed?", "options": ["By printing money", "By raising income tax", "By attracting financial inflows — selling assets to overseas investors or borrowing abroad", "By cutting government spending"]}'::jsonb, '{"answer": 2, "explain": "The extract states it directly: the UK is a net borrower and must attract net financial inflows, achieved through selling its assets to overseas investors or borrowing from the rest of the world. Taxation is the government''s budget, a separate matter entirely."}'::jsonb),
('economics:4-2-balance-of-payments:misc:32b4621b', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Trade in goods went from −112 603 to −219 291, so trade in goods increased.\"</p><p><strong>✅ The correct idea:</strong> The examiners were blunt about this on Q3(b): \"Many candidates wrote about the trade in goods and/or services increasing. This is not what the data shows, it is the deficit or surplus.\" The figures are NET values (exports minus imports), so a number moving from −112 603 to −219 291 does not mean trade increased — it means the DEFICIT grew. Likewise services rising from 95 657 to 151 339 is a growing SURPLUS. The examiners added an Assessment for learning note: \"It is recommended that students are encouraged to use key terms such as deficit or surplus when referring to the current account or trade flows and that there is a focus on the implications of a ''net value'' i.e. that international trade reflects exports and imports.\" Use the words deficit and surplus in every answer.</p>", "question": "The UK''s trade in goods figure moves from −112 603 to −219 291 (£m). The correct description is...", "options": ["Trade in goods has decreased", "The deficit on trade in goods has grown", "The surplus on trade in goods has grown", "Trade in goods has increased"]}'::jsonb, '{"answer": 1, "explain": "It is a NET figure, so a more negative number means a bigger deficit — not a change in the volume of trade. Always name it as a deficit or a surplus."}'::jsonb),
('economics:4-2-balance-of-payments:misc:ab87ff9b', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"The answer is 78 296.\"</p><p><strong>✅ The correct idea:</strong> That drops a mark on almost every calculation in this topic, and the examiners say so on four separate questions. On Q3(a): \"This question was generally well answered, although a significant number of candidates did not include the £ sign or millions\" — the mark scheme states \"Only 1 mark if minus sign (or deficit) missing OR if units (£ million) omitted.\" On Q11: \"some omitted the $ sign, million or negative symbol.\" On Q17(a): \"some candidates omitted the £ sign\", where the mark scheme demands the answer \"must include the £ sign and the minus sign or refer to a deficit.\" And Q21 states \"If millions (m) omitted, then maximum 1 mark.\" So write <strong>−£78 296 million</strong>, or \"a deficit of £78 296 million\". Three things every time: the sign (or the word deficit), the currency symbol, and the units. On percentage questions the same logic applies to the % sign — Q17(b) says a correct answer without the percentage sign is worth 1 mark only.</p>", "question": "You calculate a current account balance of −78 296. To earn BOTH marks you must write...", "options": ["−78 296", "−£78 296 million (or ''a deficit of £78 296 million'')", "78 296", "£78 296"]}'::jsonb, '{"answer": 1, "explain": "The mark scheme gives only 1 mark if the minus sign (or the word deficit) is missing, OR if the units (£ million) are omitted. You need the sign, the £ and the units."}'::jsonb),
('economics:4-2-balance-of-payments:misc:fcd71cb6', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"The line on the chart goes down from 2011 to 2019, so the deficit went down.\"</p><p><strong>✅ The correct idea:</strong> This is the trap built into the Q16(a) chart, and the examiners flagged it as a Misconception: \"It is also complicated by the doubling up of the negative trend in the figures with the negative sense of the word ''deficit''.\" A deficit IS a negative number, so a line falling further below zero means the deficit is getting BIGGER, not smaller. The examiners noted: \"Weaker responses sometimes described only the downwards direction of the data without explaining that meant the deficit (which is a negative) increased.\" They also warned against the other half of the error: \"A common misconception is to purely trawl through data, quoting it without actually explaining it here is not enough.\" Quoting numbers is not explaining them. The winning technique they describe is simple — state the overall trend, add one variation within it (2016 to 2017 the deficit reduced, then grew again), and say what must have happened to exports and/or imports to cause it.</p>", "question": "On a chart of the current account balance, the line falls from −30 000 in 2011 to −95 000 in 2019. This means...", "options": ["The deficit has decreased", "The country moved into surplus", "The deficit has increased", "Exports have increased"]}'::jsonb, '{"answer": 2, "explain": "A deficit is negative, so a line moving further below zero is a GROWING deficit. The ''doubling up'' of a downward trend with the negative sense of the word deficit is exactly what the examiners flagged."}'::jsonb),
('economics:4-2-balance-of-payments:misc:0d230d1b', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"The question says ''evaluate the extent to which the government should eliminate the deficit'', so I''ll explain HOW they could do it.\"</p><p><strong>✅ The correct idea:</strong> The examiners were very specific on Q16(d)(iii): \"Candidates who answered this question well quickly realised that this question focused on ''should'' rather than purely ''how''.\" Explaining policies is analysis, not evaluation — and it answers a question that wasn''t asked. They added: \"This was a question with wording specifically asking about extent of intervention and whether the government should intervene. Judgements that focused on this exact question wording were likely to be more effective. This is a technique that may well be tested on future papers.\" Two more warnings worth heeding: \"a correct point is credited once, so it is useful to consider the use of summary-style conclusions that are purely repetitive\" — a conclusion that just repeats your paragraphs earns nothing. And on Q3(d)(ii), a 2-mark ''explain'' question: \"Many candidates identified a reasonable reason but did not explain it. A further common error/misconception was between exchange rates and interest rates.\" Identifying is 1 mark; the explanation is the second.</p>", "question": "For ''Evaluate the extent to which the UK government SHOULD try to eliminate the current account deficit'', the strongest answers...", "options": ["Focused on whether it should intervene, not just how it could", "Ended with a summary repeating earlier points", "Rewrote the extract data", "Listed as many policies as possible"]}'::jsonb, '{"answer": 0, "explain": "The examiners said good candidates \"quickly realised that this question focused on ''should'' rather than purely ''how''\", and that judgements matching the exact question wording were the most effective."}'::jsonb),
('economics:4-2-balance-of-payments:tips:c7e97a81', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'tips', 'mcq', 1, '{"readingTitle": "calculation — Calculations: sign, symbol, units — every time", "reading": "<p>Roughly a quarter of this paper''s marks are calculations, and they are lost on presentation more than on arithmetic.</p>\n<ul>\n<li><strong>Balance of trade in goods and services</strong> = balance on goods + balance on services. Work out the goods balance FIRST if the table leaves it blank: £292 867m − £412 472m = −£119 605m, then −119 605 + 85 863 = <strong>−£33 742m</strong>.</li>\n<li><strong>Current account balance</strong> = goods + services + income flows + transfers. All four, every time.</li>\n<li><strong>Percentage change</strong> = change ÷ ORIGINAL × 100. Not ÷ the new figure.</li>\n<li><strong>Deficit as % of GDP</strong> = deficit ÷ GDP × 100.</li>\n<li><strong>Converting currency:</strong> $54 692m ÷ 1.5586 = £35 090.47m. Dividing converts dollars into pounds when the rate is quoted as 1 GBP = 1.5586 USD.</li>\n<li><strong>The presentation marks:</strong> minus sign (or the word \"deficit\"), the £/$ symbol, and the units (million). The mark schemes cap you at 1 mark for missing any of them — and at 1 mark for a percentage without the % sign.</li>\n</ul>", "question": "A table gives export of goods £292 867m and import of goods £412 472m, and balance of trade in services £85 863m. The balance of trade in goods and services is...", "options": ["£205 468m", "−£33 742m", "£33 742m", "−£119 605m"]}'::jsonb, '{"answer": 1, "explain": "Goods balance = 292 867 − 412 472 = −119 605. Then −119 605 + 85 863 = −£33 742m. Note the minus sign and the units — both are needed for the second mark."}'::jsonb),
('economics:4-2-balance-of-payments:tips:28e827ef', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'tips', 'mcq', 1, '{"readingTitle": "data — Trend questions: explain it, don''t just quote it", "reading": "<p>Two marks, and a reliable structure the examiners themselves described as \"simple, but effective\".</p>\n<ul>\n<li><strong>Mark 1 — the overall trend</strong> across the exact dates named: \"overall the deficit has been increasing\".</li>\n<li><strong>Mark 2 — one variation within it, OR what must have happened to exports/imports:</strong> \"from 2016 to 2017 the deficit reduced, but since then has increased again\", or \"imports have been rising or exports falling, or both\".</li>\n<li><strong>Remember a deficit is NEGATIVE</strong> — a line falling further below zero is a GROWING deficit.</li>\n<li><strong>Comparison questions need an actual comparison:</strong> \"Germany has a surplus while the UK and USA have deficits\" — max 1 mark if you don''t compare, and just saying data is \"positive or negative\" is too vague.</li>\n<li><strong>Never trawl.</strong> Quoting figures without explaining them scores nothing.</li>\n</ul>", "question": "Explaining how Germany''s current account position differs from the UK''s and the USA''s, what is needed for BOTH marks?", "options": ["Listing all nine figures in the table", "Stating Germany''s figures are positive", "Saying Germany has a surplus while the UK and USA have deficits, and comparing them", "Explaining why Germany exports cars"]}'::jsonb, '{"answer": 2, "explain": "The mark scheme gives a max of 1 mark with no comparison: one mark for knowing whether the data means surplus or deficit, and one for the comparison. ''Positive or negative'' alone was judged too vague."}'::jsonb),
('economics:4-2-balance-of-payments:tips:7c9274a9', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'tips', 'mcq', 1, '{"readingTitle": "analyse — Analyse: developed chains, not rewritten extracts", "reading": "<p>The commonest way to lose marks here is to retell the extract. The examiners: <strong>\"Candidates who scored lower marks mostly rewrote the information in the case study with no analysis.\"</strong></p>\n<ul>\n<li><strong>Reach Level 2 by referencing the extract</strong> — but reference it to build a chain, not to repeat it. \"If there is no analysis (AO3a), then application (AO2) cannot be rewarded.\"</li>\n<li><strong>Develop the chain to the end.</strong> They criticised answers that wrote \"more competitive producers overseas resulting in demand falling for UK producers… and then nothing further\".</li>\n<li><strong>A reliable UK chain:</strong> the UK''s resources shifted to services → fewer resources for goods → UK goods are dearer/lower quality than competitors'' → exports fall and imports rise → the goods deficit grows.</li>\n<li><strong>Diagram questions:</strong> \"A maximum of 3 marks if no relevant diagram\" — half the marks gone. Fewer exports → demand for £ shifts LEFT; more imports → supply of £ shifts RIGHT; either way the exchange rate falls.</li>\n<li><strong>Match the exact currencies named</strong> in the question on your diagram and in your text.</li>\n</ul>", "question": "In a 6-mark ''analyse with a demand and supply diagram'' question, omitting the diagram caps you at...", "options": ["5 marks", "No cap — the text is enough", "4 marks", "3 marks"]}'::jsonb, '{"answer": 3, "explain": "The mark scheme states ''A maximum of 3 marks if no relevant diagram'' — you lose half the marks. The examiners also stress using the diagram''s labels throughout the written explanation."}'::jsonb),
('economics:4-2-balance-of-payments:tips:e94d0482', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — Evaluate: match every point, and answer the exact question", "reading": "<p>The structural rule from the mark scheme: <strong>\"Each aspect (AO3a) should be analysed and matched with an evaluation point (AO3b).\"</strong> Make a point, then immediately counter it with \"However…\".</p>\n<ul>\n<li><strong>Ready-made matched pairs:</strong> the deficit reflects falling demand for domestic goods → unemployment. <em>However</em>: UK unemployment is relatively low at present. / The deficit pushes the exchange rate down. <em>However</em>: a lower rate should make UK exports more competitive. / The deficit is financed by inward investment. <em>However</em>: that is why the income account is in deficit — foreign-owned assets here earn more than UK assets abroad.</li>\n<li><strong>The four evaluation levers:</strong> the SIZE of the deficit, its DURATION, WHAT is being imported (inputs needed for UK production are different from consumer goods), and whether government intervention''s benefits outweigh its costs.</li>\n<li><strong>Answer the exact wording.</strong> \"Should the government intervene\" is not \"how could it\".</li>\n<li><strong>Don''t repeat yourself in the conclusion</strong> — \"a correct point is credited once\".</li>\n<li><strong>Plan first:</strong> the examiners recommend brief, note-form chains matched to evaluation before writing.</li>\n</ul>", "question": "The mark scheme''s structural instruction for these 6-mark evaluate questions is that...", "options": ["Diagrams are required", "You should list as many points as possible", "The conclusion should summarise every paragraph", "Each analysis point should be matched with an evaluation point"]}'::jsonb, '{"answer": 3, "explain": "The mark scheme states: ''Each aspect (AO3a) should be analysed and matched with an evaluation point (AO3b)''. Point, then ''However…'', then a judgement that answers the exact question."}'::jsonb),
('economics:4-2-balance-of-payments:fib:3716d925', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'fib', 'fib', 2, '{"question": "The balance of payments records all financial transactions between a country and the ___B1___ of the world. At GCSE the focus is the ___B2___ account.", "blankOptions": {"B1": ["financial", "persistent", "rest", "deficit"], "B2": ["current", "GDP", "persistent", "falling"]}}'::jsonb, '{"blanks": {"B1": "rest", "B2": "current"}}'::jsonb),
