('economics:4-2-balance-of-payments:fib:d99679e7', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'fib', 'fib', 2, '{"question": "A ___B1___ exchange rate makes exports cheaper and imports dearer, which tends to ___B2___ the current account balance.", "blankOptions": {"B1": ["persistent", "current", "GDP", "falling"], "B2": ["deficit", "rest", "income", "improve"]}}'::jsonb, '{"blanks": {"B1": "falling", "B2": "improve"}}'::jsonb),
('economics:4-2-balance-of-payments:fib:3167f1b7', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'fib', 'fib', 2, '{"question": "How serious a deficit is depends on its cause, its size relative to ___B1___, and whether it is short-term or ___B2___.", "blankOptions": {"B1": ["GDP", "deficit", "income", "productivity"], "B2": ["persistent", "transfers", "income", "financial"]}}'::jsonb, '{"blanks": {"B1": "GDP", "B2": "persistent"}}'::jsonb),
('economics:4-2-balance-of-payments:match:6cc51ba0', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Balance of payments”?", "options": ["A record of all financial transactions between a country and the rest of the world", "Exports minus imports of physical, visible items such as cars and laptops", "Earnings on investments abroad, minus earnings paid to foreign investors here", "Records investment flows, e.g. a foreign firm buying a UK factory"]}'::jsonb, '{"answer": 0, "explain": "“Balance of payments” means: A record of all financial transactions between a country and the rest of the world"}'::jsonb),
('economics:4-2-balance-of-payments:match:1bbe56c1', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Current account”?", "options": ["More money flows out of the country than flows into it", "Trade in goods and services, plus income flows, plus transfers", "Records investment flows, e.g. a foreign firm buying a UK factory", "The four components net to zero — money in equals money out"]}'::jsonb, '{"answer": 1, "explain": "“Current account” means: Trade in goods and services, plus income flows, plus transfers"}'::jsonb),
('economics:4-2-balance-of-payments:match:576d3604', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Balance of trade”?", "options": ["The record of a country''s trade in goods and services only", "The four components net to zero — money in equals money out", "Trade in goods and services, plus income flows, plus transfers", "Exports minus imports of physical, visible items such as cars and laptops"]}'::jsonb, '{"answer": 0, "explain": "“Balance of trade” means: The record of a country''s trade in goods and services only"}'::jsonb),
('economics:4-2-balance-of-payments:match:46d1877f', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Trade in goods”?", "options": ["Exports minus imports of services such as tourism, finance and education", "The record of a country''s trade in goods and services only", "Exports minus imports of physical, visible items such as cars and laptops", "The four components net to zero — money in equals money out"]}'::jsonb, '{"answer": 2, "explain": "“Trade in goods” means: Exports minus imports of physical, visible items such as cars and laptops"}'::jsonb),
('economics:4-2-balance-of-payments:match:c7c12c35', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Trade in services”?", "options": ["Exports minus imports of services such as tourism, finance and education", "Money sent abroad with nothing received in return, e.g. foreign aid", "Trade in goods and services, plus income flows, plus transfers", "More money flows out of the country than flows into it"]}'::jsonb, '{"answer": 0, "explain": "“Trade in services” means: Exports minus imports of services such as tourism, finance and education"}'::jsonb),
('economics:4-2-balance-of-payments:match:46432547', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Income flows”?", "options": ["Exports minus imports of physical, visible items such as cars and laptops", "Earnings on investments abroad, minus earnings paid to foreign investors here", "Records investment flows, e.g. a foreign firm buying a UK factory", "Exports minus imports of services such as tourism, finance and education"]}'::jsonb, '{"answer": 1, "explain": "“Income flows” means: Earnings on investments abroad, minus earnings paid to foreign investors here"}'::jsonb),
('economics:4-2-balance-of-payments:match:0dee5e59', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Transfers”?", "options": ["Exports minus imports of services such as tourism, finance and education", "Inflows from exports, income and transfers exceed the outflows", "Money sent abroad with nothing received in return, e.g. foreign aid", "Earnings on investments abroad, minus earnings paid to foreign investors here"]}'::jsonb, '{"answer": 2, "explain": "“Transfers” means: Money sent abroad with nothing received in return, e.g. foreign aid"}'::jsonb),
('economics:4-2-balance-of-payments:match:2723e7f6', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Current account surplus”?", "options": ["Inflows from exports, income and transfers exceed the outflows", "The four components net to zero — money in equals money out", "Exports minus imports of physical, visible items such as cars and laptops", "A record of all financial transactions between a country and the rest of the world"]}'::jsonb, '{"answer": 0, "explain": "“Current account surplus” means: Inflows from exports, income and transfers exceed the outflows"}'::jsonb),
('economics:4-2-balance-of-payments:match:a52b63f6', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Current account deficit”?", "options": ["Earnings on investments abroad, minus earnings paid to foreign investors here", "The record of a country''s trade in goods and services only", "More money flows out of the country than flows into it", "A country that must attract financial inflows to finance its deficit"]}'::jsonb, '{"answer": 2, "explain": "“Current account deficit” means: More money flows out of the country than flows into it"}'::jsonb),
('economics:4-2-balance-of-payments:match:36b4ee1e', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Balanced current account”?", "options": ["Inflows from exports, income and transfers exceed the outflows", "A record of all financial transactions between a country and the rest of the world", "Money sent abroad with nothing received in return, e.g. foreign aid", "The four components net to zero — money in equals money out"]}'::jsonb, '{"answer": 3, "explain": "“Balanced current account” means: The four components net to zero — money in equals money out"}'::jsonb),
('economics:4-2-balance-of-payments:match:cdcc1ae9', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Financial account”?", "options": ["Inflows from exports, income and transfers exceed the outflows", "Money sent abroad with nothing received in return, e.g. foreign aid", "More money flows out of the country than flows into it", "Records investment flows, e.g. a foreign firm buying a UK factory"]}'::jsonb, '{"answer": 3, "explain": "“Financial account” means: Records investment flows, e.g. a foreign firm buying a UK factory"}'::jsonb),
('economics:4-2-balance-of-payments:match:726ad97a', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Net borrower”?", "options": ["Inflows from exports, income and transfers exceed the outflows", "The four components net to zero — money in equals money out", "Earnings on investments abroad, minus earnings paid to foreign investors here", "A country that must attract financial inflows to finance its deficit"]}'::jsonb, '{"answer": 3, "explain": "“Net borrower” means: A country that must attract financial inflows to finance its deficit"}'::jsonb),
('economics:4-2-balance-of-payments:match:389b502e', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Deficit as a % of GDP”?", "options": ["Exports minus imports of physical, visible items such as cars and laptops", "Inflows from exports, income and transfers exceed the outflows", "Deficit ÷ national output × 100 — how the seriousness is judged", "Exports minus imports of services such as tourism, finance and education"]}'::jsonb, '{"answer": 2, "explain": "“Deficit as a % of GDP” means: Deficit ÷ national output × 100 — how the seriousness is judged"}'::jsonb),
('economics:4-3-exchange-rates:exam:a3921c7a', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'exam', 'mcq', 1, '{"num": "Q1", "question": "A government can prevent the country''s exchange rate from rising by", "options": ["buying its own currency", "increasing interest rates", "selling its own currency", "selling its reserves of foreign currency"], "hint": "To stop the currency RISING, the government needs to push its value down, or at least stop it going up — that means increasing the SUPPLY of its own currency on the market.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — selling its own currency</strong></p>\n<ul>\n<li>Selling its own currency increases its supply on the foreign exchange market, which pushes its price down — preventing (or reversing) a rise. Buying its own currency (A), raising interest rates (B), or selling foreign currency reserves (D) would all tend to push the exchange rate UP, not prevent a rise.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-3-exchange-rates:exam:056d4b5a', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'exam', 'mcq', 1, '{"num": "Q3", "question": "All other things being equal, what would increase the volume of imports?", "options": ["A fall in interest rates", "A fall in the price level", "A new tax on imported goods", "A rise in the exchange rate"], "hint": "A rise in the exchange rate (appreciation) makes foreign goods CHEAPER for domestic buyers, so the quantity of imports bought rises.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: D — A rise in the exchange rate</strong></p>\n<ul>\n<li>A rise in the exchange rate makes imports cheaper for domestic buyers, increasing the volume bought. A new tax on imports (C) would REDUCE the volume, and a fall in interest rates (A) or the price level (B) does not directly change the price of imports in the same way.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates correctly identified the correct answer (D).</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-3-exchange-rates:exam:c754bbbe', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'exam', 'mcq', 1, '{"num": "Q4", "question": "What happened to the Sterling price of the villa for the consumer?", "options": ["Decreased by £400", "Decreased by £139.20", "Increased by £100", "Remained unchanged"], "caseStudy": "<p>A consumer is planning a holiday. They found a villa that cost €3480 when the exchange rate was £1 = €1.20. By the time they booked the villa the exchange rate had changed to £1 = €1.16.</p>", "hint": "Convert the euro price into pounds at BOTH rates by dividing: €3480 ÷ 1.20 first, then €3480 ÷ 1.16. Compare the two pound figures.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2) · Quantitative skills</h5>\n<p><strong>Answer: C — Increased by £100</strong></p>\n<ul>\n<li>At £1 = €1.20: €3480 ÷ 1.20 = £2900. At £1 = €1.16: €3480 ÷ 1.16 = £3000. The pound depreciated against the euro (buys fewer euros), so the villa became £100 MORE expensive for the UK consumer, not cheaper.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates correctly identified the correct answer (C).</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-3-exchange-rates:exam:66cfbc8a', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'exam', 'mcq', 1, '{"num": "Q5", "question": "What might cause the Sterling to US Dollar exchange rate to increase from p1 to p2?", "options": ["Incomes of US consumers increase", "Less imports are bought from the US", "The UK becomes more attractive for foreign investment", "UK goods become more desirable to US consumers"], "caseStudy": "<p>The diagram shows the supply and demand for Sterling (£) when priced in US dollars ($).</p>\n<img src=\"/images/economics/4-3-sterling-usd-supply-demand-diagram-extracted.png\" alt=\"Supply and demand diagram for Sterling priced in US dollars. The vertical axis is Price of Sterling in US Dollars, the horizontal axis is Quantity of Sterling. A downward-sloping demand curve D is shown. Two upward-sloping supply curves are shown: S1, closer to the origin, and S2, shifted left/up from S1. D crosses S1 at a lower price p1 and quantity q1; D crosses S2 at a higher price p2 and a lower quantity q2, illustrating that a leftward shift in supply from S1 to S2 raises the price of Sterling from p1 to p2\" style=\"display:block;width:100%;max-width:480px;margin:14px auto;border:1px solid var(--border);border-radius:8px;background:#fff;padding:6px;\" />", "hint": "Look at the diagram carefully: the SUPPLY curve shifts from S1 to S2 (leftward), not the demand curve. Price rises because SUPPLY of pounds fell, not because demand rose — only one option changes supply rather than demand.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Less imports are bought from the US</strong></p>\n<ul>\n<li>The diagram shows the SUPPLY curve shifting from S1 to S2 (leftward), not the demand curve. Fewer UK imports from the US means UK residents supply fewer pounds to buy dollars, so the supply of pounds falls — matching the diagram''s S1→S2 shift and raising the price from p1 to p2.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>This question had a wide range of answers, rather than the correct one, which is the impact of a change on the value of the pound.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-3-exchange-rates:exam:7acab1ef', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'exam', 'mcq', 1, '{"num": "Q6", "question": "What is the price that the UK producer will now have to pay for the raw materials?", "options": ["£2400", "£20 000", "£22 400", "£35 000"], "caseStudy": "<p>A UK producer is currently buying raw materials from the USA for $28,000. The value of the UK pound (£) in terms of the US Dollar ($) changes from £1 = $1.40 to £1 = $1.25.</p>", "hint": "Divide the DOLLAR cost by the NEW rate ($1.25), not the old one, since you''re finding the £ cost AFTER the rate changed: $28,000 ÷ 1.25.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2) · Quantitative skills</h5>\n<p><strong>Answer: C — £22 400</strong></p>\n<ul>\n<li>$28,000 ÷ $1.25 = £22,400. At the OLD rate it would have cost £20,000 (option B) — the pound has depreciated from $1.40 to $1.25, so it buys fewer dollars, and the same $28,000 of materials now costs the UK producer MORE in pounds.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates answered C correctly.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-3-exchange-rates:exam:883cabb1', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'exam', 'mcq', 1, '{"num": "Q7", "question": "Which statement is most likely to be correct?", "options": ["There was a decrease in the demand for pounds between 2014 and 2016", "There was a decrease in the supply of pounds between 2013 and 2014", "There was a fall in the rate of inflation from 2016 to 2019", "There was a loss of confidence by investors in the UK economy after 2016"], "caseStudy": "<p>The diagram shows the value of the UK pound (£) in terms of the Euro (€) from 2013 to 2022.</p>\n<img src=\"/images/economics/4-3-gbp-eur-2013-2022-chart-extracted.png\" alt=\"Line chart from the OCR exam paper showing the value of the UK pound in euros from 2013 to 2022. Values: 2013 about 1.23, 2014 about 1.20, 2015 about 1.27, 2016 about 1.37 (the peak), 2017 about 1.18, 2018 about 1.12, 2019 about 1.11, 2020 about 1.18, 2021 about 1.11, 2022 about 1.20. The pound rises steadily from 2013 to a peak in 2016, then falls sharply after 2016 before fluctuating between about 1.11 and 1.20\" style=\"display:block;width:100%;max-width:540px;margin:14px auto;border:1px solid var(--border);border-radius:8px;background:#fff;padding:6px;\" />", "hint": "The chart peaks in 2016 then falls sharply — this matches the timing of the Brexit referendum (2016). A is wrong because the rate RISES from 2014 to 2016 (more demand, not less); the chart shows an exchange rate, not an inflation rate, so C can''t be read off it.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: D — There was a loss of confidence by investors in the UK economy after 2016</strong></p>\n<ul>\n<li>The pound peaks at 1.37 euros in 2016 and then falls sharply — consistent with a loss of investor confidence after the 2016 Brexit referendum. The rate RISES between 2014 and 2016 (ruling out A, which describes falling demand), and the chart shows an exchange rate, not an inflation rate (ruling out C).</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates answered D correctly.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-3-exchange-rates:exam:32fc7a94', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'exam', 'mcq', 1, '{"num": "Q11", "question": "Which of the following statements is correct?", "options": ["Exports from the UK to the US became more expensive between 2016 and 2017", "Exports from the UK to the US became more expensive between 2019 and 2020", "Exports from the US to the UK became less expensive between 2018 and 2019", "Exports from the US to the UK became more expensive between 2017 and 2018"], "caseStudy": "<p>The table shows the exchange rate of the UK pound (£) against the US dollar ($).</p>\n<table style=\"width:100%;max-width:340px;margin:12px auto;border-collapse:collapse;text-align:left;font-size:14px;\">\n<tr style=\"border-bottom:1px solid var(--border);\"><th style=\"padding:6px;\">Date</th><th style=\"padding:6px;\">Exchange rate (£1)</th></tr>\n<tr><td style=\"padding:6px;\">1st January 2016</td><td style=\"padding:6px;\">$1.47</td></tr>\n<tr><td style=\"padding:6px;\">1st January 2017</td><td style=\"padding:6px;\">$1.23</td></tr>\n<tr><td style=\"padding:6px;\">1st January 2018</td><td style=\"padding:6px;\">$1.35</td></tr>\n<tr><td style=\"padding:6px;\">1st January 2019</td><td style=\"padding:6px;\">$1.27</td></tr>\n<tr><td style=\"padding:6px;\">1st January 2020</td><td style=\"padding:6px;\">$1.33</td></tr>\n</table>", "hint": "Check each period: the rate FELL 2016→2017 (pound weaker = UK exports CHEAPER, not dearer, ruling out A). The rate ROSE 2019→2020 ($1.27→$1.33, pound stronger = UK exports MORE expensive for US buyers) — matches B.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: B — Exports from the UK to the US became more expensive between 2019 and 2020</strong></p>\n<ul>\n<li>The rate rose from $1.27 (Jan 2019) to $1.33 (Jan 2020) — the pound appreciated, making UK exports more expensive in dollar terms. Checking the others: 2016→2017 the rate FELL ($1.47→$1.23), so UK exports got CHEAPER, not dearer (A false); 2018→2019 the rate FELL ($1.35→$1.27), so US exports to the UK got MORE expensive, not less (C false); 2017→2018 the rate ROSE ($1.23→$1.35), so US exports to the UK got CHEAPER, not dearer (D false).</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-3-exchange-rates:exam:b0d083c3', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'exam', 'mcq', 1, '{"num": "Q13", "question": "Which of the following is the most likely consequence for UK consumers of a fall in the UK exchange rate?", "options": ["An increase in the rate of inflation", "An increase in the standard of living", "An increase in overseas tourism", "An increase in unemployment"], "hint": "A fall (depreciation) makes imports dearer, including imported raw materials, which feeds through as cost-push inflation. The other options describe the opposite of what tends to happen.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — An increase in the rate of inflation</strong></p>\n<ul>\n<li>A fall in the exchange rate makes imports, including raw materials, more expensive, feeding through as inflation. It tends to REDUCE the standard of living (B) and REDUCE overseas tourism by UK residents, since their pounds buy less abroad (C), not increase it.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-3-exchange-rates:exam:5d6f5cc4', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'exam', 'mcq', 1, '{"num": "Q14", "question": "The diagram shows the supply and demand for the Euro expressed in Sterling (£). If the UK increases its demand for imports from countries whose currency is the Euro, which of these will happen?", "options": ["The demand curve will shift downwards to the left", "The demand curve will shift upwards to the right", "There will be no change in the position of either the supply curve or of the demand curve", "The supply curve will shift upwards to the left"], "hint": "Careful — this diagram is for the EURO (priced in £), not the pound. UK residents buying more EU imports need to acquire MORE euros, so DEMAND for euros rises — the demand curve shifts right.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: B — The demand curve will shift upwards to the right</strong></p>\n<ul>\n<li>This diagram is for the market for EUROS, priced in Sterling. UK residents buying more imports from Eurozone countries need to buy more euros to pay for them, so demand for euros rises — the demand curve shifts right, not left, and supply is unaffected.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-3-exchange-rates:exam:899d174b', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'exam', 'mcq', 1, '{"num": "Q15", "question": "Terry and June are planning a holiday to Canada. If the value of the UK pound (£) in terms of the Canadian dollar ($) is £1 = $1.75, how many dollars will they get if they exchange £500?", "options": ["$285.71", "$375.00", "$589.29", "$875.00"], "hint": "Converting FROM pounds TO dollars — multiply: £500 × 1.75.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2) · Quantitative skills</h5>\n<p><strong>Answer: D — $875.00</strong></p>\n<ul>\n<li>£500 × $1.75 = $875.00. Dividing instead of multiplying (£500 ÷ 1.75 = $285.71) is the classic trap in option A.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-3-exchange-rates:exam:407599fa', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'exam', 'mcq', 1, '{"num": "Q16", "question": "If the Swiss government allows the Swiss Franc to appreciate against the Euro, which of the following is most likely to happen?", "options": ["The number of Swiss watches exported will fall", "The price of Swiss chocolate in France will fall", "The rate of interest in Switzerland will rise", "There will be more German tourists in Switzerland"], "hint": "Appreciation makes Swiss EXPORTS more expensive abroad, so fewer are likely to be bought. Don''t confuse cause and effect: an appreciation doesn''t directly RAISE Swiss interest rates, and it makes Switzerland MORE expensive for German tourists, not less.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — The number of Swiss watches exported will fall</strong></p>\n<ul>\n<li>A stronger Franc makes Swiss exports, e.g. watches, more expensive in foreign currency terms, so export volumes are likely to fall. Swiss chocolate would become MORE expensive in France, not cheaper (B); appreciation is usually a consequence of factors like higher interest rates, not a cause of them (C); and a stronger Franc makes Switzerland MORE expensive for German tourists, discouraging visits (D).</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>Several candidates answered ''C'', demonstrating a confusion between interest rates and exchange rates.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-3-exchange-rates:exam:a9fde655', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'exam', 'mcq', 1, '{"num": "Q17", "question": "Which of the following will cause a country''s exchange rate to fall? Increased", "options": ["balance of payments surplus", "demand for its exports", "demand for its imports", "rate of interest"], "hint": "Increased demand for IMPORTS means more of the home currency is SUPPLIED (sold) to buy foreign currency — an increase in supply pushes the price DOWN. The other three options would all tend to push the exchange rate UP.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — Increased demand for its imports</strong></p>\n<ul>\n<li>Buying more imports means more of the home currency must be supplied (sold) to buy the foreign currency needed, so supply rises and the exchange rate falls. An increased balance of payments surplus (A), increased demand for exports (B), and a higher interest rate (D) would all tend to RAISE the exchange rate instead.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-3-exchange-rates:exam:17b4003e', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'exam', 'mcq', 1, '{"num": "Q18", "question": "James and Jane are returning from a holiday in Slovenia and want to convert their euros (€) into UK pounds (£). If the value of the UK pound in terms of the euro is £1 = €1.15, how many pounds will they get if they exchange €300?", "options": ["£260.87", "£298.65", "£302.94", "£345.00"], "hint": "Converting FROM euros TO pounds — divide: €300 ÷ 1.15.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2) · Quantitative skills</h5>\n<p><strong>Answer: A — £260.87</strong></p>\n<ul>\n<li>€300 ÷ 1.15 = £260.87. Multiplying instead of dividing (€300 × 1.15 = £345.00) is the trap in option D.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-3-exchange-rates:exam:5625b451', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'exam', 'mcq', 1, '{"num": "Q19", "question": "The exchange rate of the UK Pound against the US Dollar depreciates from £1.00 = $1.50 to £1.00 = $1.00. As a result of this:", "options": ["the volume of UK exports to the US will fall", "the volume of UK imports of US goods will rise", "UK consumers will pay more for US goods", "US consumers will pay more for UK goods"], "hint": "A depreciation makes UK exports CHEAPER for US buyers (so export volume should RISE, not fall) and makes US goods MORE expensive for UK buyers (so import volume should FALL, and UK consumers pay more).", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: C — UK consumers will pay more for US goods</strong></p>\n<ul>\n<li>The pound now buys fewer dollars, so US goods cost UK consumers more in pounds. This depreciation should INCREASE UK export volumes to the US (ruling out A) and DECREASE the volume of US imports bought (ruling out B), while US consumers pay LESS for UK goods, not more (ruling out D).</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-3-exchange-rates:mcq:b4ae304c', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'mcq', 'mcq', 1, '{"question": "The exchange rate is best defined as...", "options": ["The total value of a country''s exports", "The rate of inflation in a country", "The interest rate set by the central bank", "The price of one currency expressed in terms of another"]}'::jsonb, '{"answer": 3, "explain": "The exchange rate is simply a price — the price of one currency in terms of another, e.g. £1 = $1.25."}'::jsonb),
('economics:4-3-exchange-rates:mcq:a8d2090e', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'mcq', 'mcq', 1, '{"question": "Under the UK''s floating exchange rate system, the value of the pound is determined by...", "options": ["The Bank of England fixing a target rate", "Government decree", "The price of gold", "The demand for and supply of pounds on foreign exchange markets"]}'::jsonb, '{"answer": 3, "explain": "A floating exchange rate is set purely by market forces — demand for and supply of the currency — not by the government fixing its value."}'::jsonb),
('economics:4-3-exchange-rates:mcq:af1262dc', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'mcq', 'mcq', 1, '{"question": "A UK exporter selling more goods to the USA will cause...", "options": ["An increase in the demand for pounds", "No change in the foreign exchange market", "An increase in the supply of pounds", "A decrease in the demand for pounds"]}'::jsonb, '{"answer": 0, "explain": "US buyers must acquire pounds to pay for UK exports, so more exports mean more DEMAND for pounds — exports always sit on the demand side."}'::jsonb),
('economics:4-3-exchange-rates:mcq:6d63944f', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'mcq', 'mcq', 1, '{"question": "UK consumers buying more imported goods from China will cause...", "options": ["An increase in the demand for pounds", "A decrease in the demand for the Chinese yuan", "An increase in the supply of pounds", "A decrease in the supply of pounds"]}'::jsonb, '{"answer": 2, "explain": "UK residents must sell pounds to acquire the foreign currency needed to pay for imports, so more imports mean more SUPPLY of pounds."}'::jsonb),
('economics:4-3-exchange-rates:mcq:6cca45d7', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'mcq', 'mcq', 1, '{"question": "If £1 = $2.00 changes to £1 = $1.50, the pound has...", "options": ["Depreciated", "Remained fixed", "Appreciated", "Been devalued by the government"]}'::jsonb, '{"answer": 0, "explain": "The pound now buys fewer dollars, so it has fallen in value — depreciated. ''Devalued'' only applies under a FIXED exchange rate system, not the pound''s floating one."}'::jsonb),
('economics:4-3-exchange-rates:mcq:2889726e', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'mcq', 'mcq', 1, '{"question": "A UK tourist exchanges £600 at a rate of £1 = $1.30. How many dollars do they receive?", "options": ["$600.00", "$830.00", "$780.00", "$461.54"]}'::jsonb, '{"answer": 2, "explain": "Converting FROM pounds TO dollars means multiplying: £600 × 1.30 = $780.00."}'::jsonb),
('economics:4-3-exchange-rates:mcq:4c48d6c2', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'mcq', 'mcq', 1, '{"question": "A holiday in the US costs $960. At £1 = $1.20, how much is this in pounds?", "options": ["£1,152", "£960", "£80", "£800"]}'::jsonb, '{"answer": 3, "explain": "Converting FROM dollars TO pounds means dividing: $960 ÷ 1.20 = £800."}'::jsonb),
('economics:4-3-exchange-rates:mcq:00bb3f72', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'mcq', 'mcq', 1, '{"question": "Which of the following would most likely cause the pound to APPRECIATE against the euro?", "options": ["A rise in UK inflation relative to the Eurozone", "A fall in UK interest rates relative to the Eurozone", "Speculators expecting the pound to fall", "A rise in UK interest rates relative to the Eurozone"]}'::jsonb, '{"answer": 3, "explain": "Higher UK rates (relative to the Eurozone) attract foreign savers seeking the better return, increasing demand for pounds and causing appreciation. The other three options would all cause depreciation."}'::jsonb),
('economics:4-3-exchange-rates:mcq:bd12e517', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'mcq', 'mcq', 1, '{"question": "An appreciation of the pound is most likely to benefit which group?", "options": ["UK firms competing against cheap imports", "UK consumers buying imported goods", "UK tourism businesses hosting foreign visitors", "UK exporters selling goods to the US"]}'::jsonb, '{"answer": 1, "explain": "Appreciation makes imports cheaper, benefiting consumers who buy them. It tends to HARM exporters, tourism businesses (the UK becomes dearer for visitors) and firms competing with now-cheaper imports."}'::jsonb),
('economics:4-3-exchange-rates:mcq:b16ab93b', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'mcq', 'mcq', 1, '{"question": "A depreciation of the pound is most likely to cause which problem for the UK economy?", "options": ["A fall in the competitiveness of UK exports", "A stronger current account deficit", "Cheaper foreign holidays for UK residents", "Cost-push inflation, as imported raw materials become more expensive"]}'::jsonb, '{"answer": 3, "explain": "A depreciation makes imported inputs dearer, which firms pass on as higher prices — cost-push inflation. It tends to IMPROVE export competitiveness and the current account, and makes foreign holidays MORE expensive, not cheaper."}'::jsonb),
('economics:4-3-exchange-rates:tf:c40daea6', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'tf', 'tf', 1, '{"question": "A rise in the exchange rate is called depreciation."}'::jsonb, '{"answer": false, "explain": "A RISE in the exchange rate is called appreciation. Depreciation is a FALL — the two are opposites, and this is a common mix-up."}'::jsonb),
('economics:4-3-exchange-rates:tf:6f9f1d85', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'tf', 'tf', 1, '{"question": "Under a floating exchange rate, the government fixes the value of the currency."}'::jsonb, '{"answer": false, "explain": "Under a floating system the value is set purely by demand and supply on foreign exchange markets, not by government decree — that''s how a FIXED system works instead."}'::jsonb),
('economics:4-3-exchange-rates:tf:2ddbb7e0', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'tf', 'tf', 1, '{"question": "UK consumers buying more imports will increase the supply of pounds on foreign exchange markets."}'::jsonb, '{"answer": true, "explain": "To buy imports, UK residents must sell pounds to obtain the foreign currency needed, which increases the supply of pounds on the market."}'::jsonb),
('economics:4-3-exchange-rates:tf:2adee11d', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'tf', 'tf', 1, '{"question": "Higher UK interest rates relative to overseas tend to cause the pound to depreciate."}'::jsonb, '{"answer": false, "explain": "Higher relative interest rates ATTRACT foreign savers seeking the better return, increasing demand for pounds and causing the pound to APPRECIATE, not depreciate."}'::jsonb),
('economics:4-3-exchange-rates:tf:ea26cb0c', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'tf', 'tf', 1, '{"question": "An appreciation of the pound tends to help control inflation."}'::jsonb, '{"answer": true, "explain": "Appreciation makes imports cheaper and reduces demand for domestic output, both of which help prevent demand-pull inflation."}'::jsonb),
('economics:4-3-exchange-rates:tf:142c7d09', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'tf', 'tf', 1, '{"question": "A depreciation of the pound always benefits UK exporters, with no downsides."}'::jsonb, '{"answer": false, "explain": "While depreciation makes exports cheaper abroad, it also makes imported raw materials more expensive and can cause inflation — so it is a genuine trade-off, not a pure benefit."}'::jsonb),
('economics:4-3-exchange-rates:tf:11acab98', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'tf', 'tf', 1, '{"question": "Devaluation and depreciation mean exactly the same thing and can be used interchangeably regardless of the exchange rate system."}'::jsonb, '{"answer": false, "explain": "Devaluation is the term for a deliberate fall under a FIXED exchange rate system; depreciation is the term for a market-driven fall under a FLOATING system like the pound''s."}'::jsonb),
('economics:4-3-exchange-rates:tf:32d1cd15', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'tf', 'tf', 1, '{"question": "A stronger pound makes it cheaper for UK residents to go on holiday abroad."}'::jsonb, '{"answer": true, "explain": "Appreciation means each pound buys more foreign currency, so foreign holidays and spending abroad become cheaper for UK residents."}'::jsonb),
('economics:4-3-exchange-rates:learn:9ae30867', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'learn', 'mcq', 1, '{"readingTitle": "What is the exchange rate? Supply, demand and the float", "reading": "<p><strong>The exchange rate is the price of one currency expressed in terms of another</strong> — e.g. £1 = $1.25. The pound is a <strong>floating exchange rate</strong>, which means its value is NOT fixed by the government but determined purely by the <strong>demand for and supply of pounds</strong> on foreign exchange markets — exactly the same demand/supply logic you already know from ordinary markets, just applied to a currency instead of a good.</p>\n<h4>Where demand for pounds comes from</h4>\n<ul>\n<li>Overseas buyers who want to purchase UK <strong>exports</strong> (goods and services) — they must first buy pounds to pay for them.</li>\n<li>Foreign savers who want to <strong>invest</strong> in UK bank accounts, UK businesses, or UK property.</li>\n<li><strong>Speculators</strong> who believe the pound''s value will rise.</li>\n</ul>\n<h4>Where supply of pounds comes from</h4>\n<ul>\n<li>UK residents who want to buy <strong>imports</strong> — they must sell pounds to buy the foreign currency needed to pay for them.</li>\n<li>UK savers and firms who want to invest abroad.</li>\n<li>Speculators who believe the pound''s value will fall.</li>\n</ul>\n<h4>Appreciation and depreciation — get the direction right every time</h4>\n<ul>\n<li><strong>Appreciation</strong> (a RISE in the exchange rate) = the pound is worth MORE — one pound buys MORE foreign currency. Caused by a rightward shift in demand for pounds, OR a decrease (leftward shift) in supply of pounds.</li>\n<li><strong>Depreciation</strong> (a FALL in the exchange rate) = the pound is worth LESS — one pound buys FEWER foreign currency. Caused by a rightward shift in supply of pounds, OR a decrease (leftward shift) in demand for pounds.</li>\n<li>Under a FIXED exchange rate system the equivalent terms are <strong>revaluation</strong> (up) and <strong>devaluation</strong> (down) — worth knowing they exist, but the GCSE focus is the floating pound.</li>\n</ul>", "question": "A rise in the exchange rate of the pound is called...", "options": ["Appreciation", "Revaluation", "Depreciation", "Devaluation"]}'::jsonb, '{"answer": 0, "explain": "A rise in a FLOATING currency''s value is called appreciation. Devaluation and revaluation are the equivalent terms under a FIXED exchange rate system, where the government sets the change deliberately."}'::jsonb),
('economics:4-3-exchange-rates:learn:55ff21ae', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'learn', 'mcq', 1, '{"readingTitle": "What shifts demand and supply of a currency", "reading": "<p>Six drivers push the exchange rate in <strong>opposite</strong> directions depending on which side of the market they hit. Learn the pattern once, then apply it either way.</p>\n<h4>What increases DEMAND for pounds (appreciation)</h4>\n<ul>\n<li><strong>UK goods gain a reputation for quality</strong> → more demand for exports → more demand for £.</li>\n<li><strong>Improved UK productivity or lower UK inflation (relative to trading partners)</strong> → lower costs → more competitive exports → more demand for £.</li>\n<li><strong>Rising incomes abroad</strong> → foreigners can afford more UK exports → more demand for £.</li>\n<li><strong>Higher UK interest rates (relative to overseas)</strong> → foreign savers move funds into UK banks to earn the better return → more demand for £. (Link to 3.6 monetary policy.)</li>\n<li><strong>Lower UK corporation tax</strong> → firms keep more profit → attracts foreign investment → more demand for £.</li>\n<li><strong>Speculation</strong> that the pound will rise → speculators buy pounds now.</li>\n</ul>\n<h4>What increases SUPPLY of pounds (depreciation)</h4>\n<ul>\n<li><strong>Foreign goods gain a reputation for quality</strong> → more UK demand for imports → more £ sold to buy foreign currency.</li>\n<li><strong>Foreign productivity gains or lower foreign inflation</strong> → cheaper imports → more £ supplied.</li>\n<li><strong>Rising UK incomes</strong> → UK consumers buy more imports → more £ supplied.</li>\n<li><strong>Lower UK interest rates (relative to overseas)</strong> → UK savers move funds abroad for a better return → more £ supplied.</li>\n<li><strong>Lower foreign corporation tax</strong> → attracts UK firms to invest abroad, e.g. Tesco operating in over 10 countries → more £ supplied.</li>\n<li><strong>Speculation</strong> that the pound will fall → speculators sell pounds now.</li>\n</ul>\n<p><strong>The classic exam trap:</strong> it is easy to get demand and supply the wrong way round. Remember: foreigners buying UK EXPORTS = they DEMAND pounds. UK residents buying IMPORTS = UK residents SUPPLY pounds (because they must sell pounds to get the foreign currency).</p>", "question": "Higher UK interest rates relative to overseas most directly cause...", "options": ["An increase in the supply of pounds", "A decrease in demand for pounds", "An increase in demand for pounds, as foreign savers seek the better return", "No change to the exchange rate"]}'::jsonb, '{"answer": 2, "explain": "Higher UK rates make holding pounds in a UK bank more rewarding, so foreign savers move funds INTO the UK to take advantage — increasing demand for pounds and causing appreciation."}'::jsonb),
('economics:4-3-exchange-rates:learn:1555780f', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'learn', 'mcq', 1, '{"readingTitle": "The effects of appreciation and depreciation — output, inflation, current account", "reading": "<p>Every exam question about the EFFECTS of an exchange rate change is really asking you to run the same chain of reasoning, just in whichever direction the question specifies.</p>\n<h4>Output and employment</h4>\n<ul>\n<li><strong>Appreciation (rise):</strong> exports become more expensive abroad (less overseas demand) and imports become cheaper (domestic firms lose sales too) → lower demand for domestic output → lower output → fewer workers needed.</li>\n<li><strong>Depreciation (fall):</strong> the opposite — cheaper exports and a better ability to compete against imports at home → higher output → more workers needed.</li>\n</ul>\n<h4>Inflation</h4>\n<ul>\n<li><strong>Appreciation</strong> → lower demand for domestic products AND cheaper imported inputs → helps PREVENT demand-pull inflation.</li>\n<li><strong>Depreciation</strong> → higher demand for domestic products AND dearer imported inputs → can CAUSE inflation (both demand-pull and cost-push).</li>\n</ul>\n<h4>Firms that import raw materials or components</h4>\n<ul>\n<li><strong>Appreciation</strong> → cheaper imported inputs, lower costs of production.</li>\n<li><strong>Depreciation</strong> → more expensive imported inputs, higher costs of production.</li>\n</ul>\n<h4>The current account (link to 4.2)</h4>\n<ul>\n<li><strong>Appreciation</strong> → fewer exports, more imports → likely to WIDEN a current account deficit.</li>\n<li><strong>Depreciation</strong> → more exports, fewer imports → likely to IMPROVE the current account (move towards surplus).</li>\n</ul>\n<p><strong>The trade-off that drives every evaluate question here:</strong> a weak pound helps exporters but stokes inflation; a strong pound curbs inflation but hurts exporters. There is no single \"right\" exchange rate — only trade-offs.</p>", "question": "A depreciation of the pound is most likely to...", "options": ["Increase cost-push inflation, as imported inputs become dearer", "Make UK exports less competitive abroad", "Prevent demand-pull inflation", "Widen the current account deficit"]}'::jsonb, '{"answer": 0, "explain": "A depreciation makes imported raw materials and components more expensive, which firms pass on as higher prices — cost-push inflation. It tends to IMPROVE the current account and make exports MORE competitive, not less."}'::jsonb),
('economics:4-3-exchange-rates:learn:37646d15', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'learn', 'mcq', 1, '{"readingTitle": "Effects on consumers and producers — the exam''s favourite evaluate", "reading": "<p>Questions on this paper repeatedly ask you to evaluate the impact on CONSUMERS and PRODUCERS by name — read which group the question specifies and don''t drift.</p>\n<h4>Consumers</h4>\n<ul>\n<li><strong>Imported goods:</strong> appreciation makes them cheaper, with more choice and better quality available; depreciation makes them more expensive with less choice.</li>\n<li><strong>Money left over / quality of life:</strong> higher after an appreciation, lower after a depreciation.</li>\n<li><strong>Foreign holidays:</strong> cheaper after an appreciation (more foreign currency per £); more expensive after a depreciation.</li>\n<li><strong>Interest rates:</strong> appreciation links to lower inflation, so the central bank may CUT interest rates — good for borrowers. Depreciation links to higher inflation, so the central bank may RAISE interest rates — bad for borrowers.</li>\n</ul>\n<h4>Producers</h4>\n<ul>\n<li><strong>Imported raw materials/components:</strong> cheaper after appreciation, dearer after depreciation.</li>\n<li><strong>Exporters:</strong> appreciation makes their goods more expensive abroad, likely fewer sales; depreciation makes them cheaper abroad, likely more sales.</li>\n<li><strong>UK tourism/hospitality:</strong> benefits from depreciation, since the UK becomes cheaper for overseas visitors.</li>\n<li><strong>Overseas-holiday firms</strong> (selling holidays abroad to UK customers) benefit from appreciation, since the whole holiday costs less.</li>\n</ul>\n<h4>Real extract-based evaluation levers</h4>\n<ul>\n<li>The SIZE of the change — a small movement in the exchange rate has little impact; a large one matters more.</li>\n<li>The LENGTH of time the change lasts — a short-lived swing has minimal effect; a sustained shift matters more.</li>\n<li>Price elasticity of demand (PED) — inelastic exports may not lose much volume even after becoming more expensive, so revenue might still rise, at least until buyers find substitutes.</li>\n<li>Whether the change is passed on in full to the final price paid by consumers.</li>\n</ul>", "question": "A UK firm that imports raw materials will benefit most from...", "options": ["A fall in the price of its own product", "An appreciation of the pound", "A rise in UK interest rates only", "A depreciation of the pound"]}'::jsonb, '{"answer": 1, "explain": "An appreciation makes the foreign currency needed to buy imported raw materials cheaper in pound terms, lowering the firm''s costs of production."}'::jsonb),
('economics:4-3-exchange-rates:misc:886dbf4e', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Higher UK interest rates mean British savers move MORE money abroad, increasing the supply of pounds.\"</p><p><strong>✅ The correct idea:</strong> This gets the direction backwards, and it''s a real misconception the mark scheme calls out by name: ''Some candidates confused the increase with saving and less supply of pounds in the foreign exchange market.'' Higher UK rates make the UK MORE attractive to save in — so foreign savers bring funds INTO the UK (demand for £ rises), and British savers have LESS reason to send money abroad (so supply of £ may fall, not rise). Either route raises the pound''s value. A genuinely sophisticated version, which examiners noted was rare, links higher rates to reduced consumption, which reduces imports and therefore reduces supply of £ too. Whichever route you pick, higher UK interest rates relative to overseas always point the same way: appreciation.</p>", "question": "Higher UK interest rates (relative to overseas) are most likely to cause the pound to...", "options": ["Appreciate, because foreign savers bring funds into the UK to earn the better return", "Stay exactly the same", "Depreciate, because imports become cheaper", "Depreciate, because savers export more money"]}'::jsonb, '{"answer": 0, "explain": "Higher UK rates attract foreign savers, raising demand for £ (or reduce British saving abroad, lowering supply of £) — both point to appreciation, not depreciation."}'::jsonb),
('economics:4-3-exchange-rates:misc:b7d68a90', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"£54 million exported at $1.60 to the pound converts to £86.4 million.\"</p><p><strong>✅ The correct idea:</strong> The maths is right but the currency symbol is wrong — and the mark scheme flags this exact error as a common misconception: candidates writing ''to write £86.4 million rather than using a dollar sign ($).'' The question asked for the value IN US DOLLARS, so the answer must be labelled $86.4 million. Whenever a calculation converts a figure INTO a different currency, the final answer needs to carry THAT currency''s symbol, not the one you started with — this rule cost real marks on this exact question.</p>", "question": "You correctly calculate that £54 million converts to 86.4 million in US dollars. How should you write the final answer?", "options": ["86.4 million pounds", "£86.4 million", "$86.4 million", "€86.4 million"]}'::jsonb, '{"answer": 2, "explain": "The question asked for the value in US dollars, so the answer must use the $ sign — using £ (the currency you started FROM, not converted TO) is the exact mistake examiners flagged."}'::jsonb),
('economics:4-3-exchange-rates:misc:97a27358', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Labelling the curves on a currency diagram AS and AD, just like a macroeconomy diagram.\"</p><p><strong>✅ The correct idea:</strong> The mark scheme is direct about this: ''A common misconception is to use AS or AD when labelling the curves. The graph is for the pound sterling on international foreign exchange markets, therefore the curves should be labelled Supply (S) and Demand (D).'' AS and AD refer to aggregate supply and aggregate demand for the WHOLE economy''s output — a completely different diagram. A currency market diagram, like a diagram for any other market, needs ordinary Supply (S) and Demand (D) curves, with the price of the currency (in another currency) on the vertical axis and the quantity of currency traded on the horizontal axis.</p>", "question": "On a diagram showing the market for pounds sterling, the two curves should be labelled...", "options": ["S and D", "MPC and MPS", "LRAS and AD", "AS and AD"]}'::jsonb, '{"answer": 0, "explain": "The exam mark scheme explicitly warns against AS/AD — those belong to a macroeconomy diagram. A currency market is a normal market, so it needs ordinary Supply (S) and Demand (D) curves."}'::jsonb),
('economics:4-3-exchange-rates:misc:3540cd24', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"If the Swiss Franc appreciates, Swiss interest rates must rise as a result.\"</p><p><strong>✅ The correct idea:</strong> This reverses cause and effect, and the examiners noted it directly: ''Several candidates answered ''C'' demonstrating a confusion between interest rates and exchange rates.'' On this paper the link usually runs the OTHER way: a RISE in interest rates can CAUSE a currency to appreciate, by attracting foreign savers. An appreciation happening for some other reason (rising exports, foreign investment, speculation) does not automatically cause interest rates to move at all — interest rates are set separately, typically by a central bank pursuing its own objectives like price stability. Keep the two variables clearly separate, and only link them in the specific direction a question''s evidence supports.</p>", "question": "Why is it wrong to assume an appreciating currency automatically causes interest rates to rise?", "options": ["Because only the government can change the exchange rate", "Because it reverses the usual direction — higher interest rates tend to CAUSE appreciation, not the other way round by default", "Because interest rates and exchange rates are unrelated in every case", "Because exchange rates never affect an economy"]}'::jsonb, '{"answer": 1, "explain": "The exam paper repeatedly uses higher interest rates as a CAUSE of appreciation. Assuming the reverse — that appreciation causes rates to rise — is the confusion examiners reported."}'::jsonb),
('economics:4-3-exchange-rates:misc:a57a8f28', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Buying more UK exports means UK residents supply more pounds.\"</p><p><strong>✅ The correct idea:</strong> This is the single most-tested trap in the whole topic, and it appears throughout this paper''s mark schemes — for example the model answer for ''analyse how an increase in demand for the pound would affect its exchange rate'' is built entirely on ''increase in demand for the pound... due to more exports paid in pounds'', and another question offers ''a decrease in demand for pounds (less inflow of funds) OR an increase in supply (greater outflow of funds)'' as the two valid routes for a FALLING pound. The rule never changes: when FOREIGNERS buy UK EXPORTS, THEY must acquire pounds to pay for them — that is DEMAND for pounds, from the foreign buyer''s side. When UK RESIDENTS buy IMPORTS, THEY must sell pounds to acquire the foreign currency — that is SUPPLY of pounds, from the UK side. Mixing these up was described by examiners as producing ''a wide range of answers, rather than the correct one'' on a related diagram question. Before writing about any currency-market shift, always ask: who is doing the buying, and which currency are THEY giving up?</p>", "question": "A rise in the volume of UK exports sold to Japan will most directly cause...", "options": ["An increase in the demand for pounds, as Japanese buyers acquire pounds to pay for the goods", "A decrease in the demand for pounds", "No change in the market for pounds", "An increase in the supply of pounds"]}'::jsonb, '{"answer": 0, "explain": "Japanese buyers of UK exports must first acquire pounds to pay for them — that is an increase in DEMAND for pounds, not supply. Exports always sit on the demand side of the pound market."}'::jsonb),
('economics:4-3-exchange-rates:tips:4283312c', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'tips', 'mcq', 1, '{"readingTitle": "calculation — Calculations: pick multiply or divide, and label the right currency", "reading": "<p>Every currency calculation on this paper needs the SAME two checks: which way are you converting, and which currency symbol goes on the final answer?</p>\n<ul>\n<li><strong>Converting FROM the base currency (e.g. £ TO $):</strong> MULTIPLY by the rate. £54 million × $1.60 = $86.4 million.</li>\n<li><strong>Converting TO the base currency (e.g. € TO £):</strong> DIVIDE by the rate. €5700 ÷ 1.14 = £5000.</li>\n<li><strong>Label the currency you converted INTO, not the one you started from.</strong> A real mark scheme flags writing \"£86.4 million\" instead of \"$86.4 million\" as a common misconception — 1 mark is lost for the wrong symbol even with correct working.</li>\n<li><strong>Simple differences don''t need conversion at all</strong> — one question just subtracts two rates from the same table (1.37 − 1.12 = 0.25 euros) and still requires you to STATE the currency (euros) to get both marks.</li>\n</ul>", "question": "A UK firm earns €8000 from sales in Germany. At a rate of £1 = €1.25, its income in pounds is...", "options": ["€10 000 — multiply by the rate", "£10 000 — multiply by the rate", "£6 400 — divide by the rate", "£8 000 — no conversion needed"]}'::jsonb, '{"answer": 2, "explain": "Converting FROM euros TO pounds means dividing by the rate: €8000 ÷ 1.25 = £6400. Multiplying would give the wrong answer and the wrong direction of conversion."}'::jsonb),
('economics:4-3-exchange-rates:tips:1c64303d', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'tips', 'mcq', 1, '{"readingTitle": "diagram — Diagrams: label S and D, show the shift, and don''t skip it", "reading": "<p>Every 6-mark \"analyse with a diagram\" question on this paper caps your marks hard if the diagram is missing or wrong.</p>\n<ul>\n<li><strong>Label the curves S and D — never AS/AD.</strong> A real mark scheme calls out AS/AD labelling as a common misconception; this is a market for a CURRENCY, not a macroeconomy diagram.</li>\n<li><strong>Show which curve shifts and which way.</strong> An increase in demand for £ = D shifts right; a rise in the supply of £ = S shifts right; a widening current account deficit could be modelled either as D shifting left (fewer exports) or S shifting right (more imports) — both are accepted.</li>\n<li><strong>No diagram, or an incorrect one, caps your mark hard.</strong> One mark scheme caps at 5 with a partially correct diagram, 4 with none at all; another caps at just 3 marks with no relevant diagram.</li>\n<li><strong>Use the question''s own currency pair.</strong> If the question asks about £ against $, don''t drift into £ against € — examiners specifically recommend matching your diagram and text to \"the exact question wording.\"</li>\n</ul>", "question": "On a 6-mark ''analyse, with the aid of a diagram'' question, what happens if you write a full, correct written analysis but include no diagram at all?", "options": ["Nothing — diagrams are optional extras", "You automatically score 0", "Your mark is capped at a lower maximum, even if the written analysis is excellent", "You get full marks if the writing is detailed enough"]}'::jsonb, '{"answer": 2, "explain": "The mark schemes are explicit: a missing diagram caps the maximum achievable mark (e.g. 4 out of 6), regardless of how good the written analysis is."}'::jsonb),
('economics:4-3-exchange-rates:tips:134930ab', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — Evaluate: name every group the question asks for, and finish the chain", "reading": "<p>One examiner''s \"Assessment for learning\" note is the single most useful sentence on this paper: candidates \"often started a point correctly... but did not always develop a chain of reasoning fully... missing out the middle section.\"</p>\n<ul>\n<li><strong>Finish the chain.</strong> Don''t stop at \"producers lose demand\" — explain WHY (their goods are now more expensive abroad) and then WHAT FOLLOWS (lower profit, possible redundancies).</li>\n<li><strong>Reference every named group.</strong> One mark scheme states plainly: \"In order to reach Level 3, there must be reference to consumers AND producers.\" If a question names two groups, dropping one caps you below the top band.</li>\n<li><strong>Evaluation is not two disconnected points.</strong> Examiners criticised answers that mentioned a falling cost for producers without linking it back to whether that offsets the fall in demand — always connect your two sides.</li>\n<li><strong>End with a real judgement</strong> naming what it depends on: the SIZE of the change, how LONG it lasts, and the price elasticity of demand for the goods affected are the three levers used across nearly every evaluate question on this paper.</li>\n</ul>", "question": "A question asks you to ''evaluate the extent to which a rise in the pound could affect UK consumers and producers.'' What is required to reach the top level (Level 3)?", "options": ["A long answer with lots of data", "Just a strong personal opinion at the end", "Reference to BOTH consumers and producers, with application, analysis and evaluation all present", "Only discussing the group you find easiest"]}'::jsonb, '{"answer": 2, "explain": "The mark scheme is explicit that Level 3 needs application (AO2), analysis (AO3a) AND evaluation (AO3b) — and reference to every group the question names."}'::jsonb),
('economics:4-3-exchange-rates:tips:a82930d7', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'tips', 'mcq', 1, '{"readingTitle": "definition — State/Explain: two precise elements, and match the exact currency", "reading": "<p>Short-answer questions reward PRECISION over length.</p>\n<ul>\n<li><strong>\"State two...\" questions need two DISTINCT, named answers</strong> — 1 mark each. Writing just \"inflation\" for \"state two economic objectives\" was flagged as \"too vague\", because inflation control isn''t itself a named objective (the objective is PRICE STABILITY).</li>\n<li><strong>\"Explain what is meant by a rise in the exchange rate\" needs TWO elements</strong>: (1) more foreign currency can be bought (2) with one unit of the home currency. Either half alone is worth 1 mark.</li>\n<li><strong>\"State what is meant by imports\" needs BOTH</strong>: goods AND services bought from abroad, PLUS the outflow of money in exchange. \"A good bought from another country\" alone drops the services element and caps you at 1 mark.</li>\n<li><strong>Match the currency named in the question.</strong> Examiners specifically recommend that \"candidates match their responses to the currency reference in the exact question wording\" — if a question is about the pound against the dollar, keep your whole answer in £/$ terms, not £/€.</li>\n</ul>", "question": "For ''state two economic objectives that monetary policy can achieve'', which answer would be marked as too vague to credit?", "options": ["A balance/surplus on the balance of payments", "Controlling inflation", "Price stability", "Low unemployment"]}'::jsonb, '{"answer": 1, "explain": "Examiners noted candidates who simply wrote ''inflation'' or similar were too vague — the actual objective is named PRICE STABILITY, which IS creditable."}'::jsonb),
('economics:4-3-exchange-rates:fib:b0f020f2', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'fib', 'fib', 2, '{"question": "A ___B1___ in the exchange rate means the pound is worth more, while a ___B2___ means it is worth less.", "blankOptions": {"B1": ["more expensive", "depreciation", "rise", "appreciate"], "B2": ["fall", "demand", "more expensive", "revaluation"]}}'::jsonb, '{"blanks": {"B1": "rise", "B2": "fall"}}'::jsonb),
('economics:4-3-exchange-rates:fib:a2deafb3', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'fib', 'fib', 2, '{"question": "The exchange rate is determined by the ___B1___ for and ___B2___ of a currency on foreign exchange markets.", "blankOptions": {"B1": ["more expensive", "depreciation", "devaluation", "demand"], "B2": ["supply", "fall", "depreciate", "cheaper"]}}'::jsonb, '{"blanks": {"B1": "demand", "B2": "supply"}}'::jsonb),
('economics:4-3-exchange-rates:fib:2804f68f', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'fib', 'fib', 2, '{"question": "Buying UK exports means foreigners must ___B1___ pounds, while UK residents buying imports must ___B2___ pounds.", "blankOptions": {"B1": ["demand", "depreciate", "appreciation", "depreciation"], "B2": ["appreciate", "supply", "devaluation", "appreciation"]}}'::jsonb, '{"blanks": {"B1": "demand", "B2": "supply"}}'::jsonb),
('economics:4-3-exchange-rates:fib:76dec6c4', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'fib', 'fib', 2, '{"question": "A rise in the exchange rate is also called ___B1___; a fall is also called ___B2___.", "blankOptions": {"B1": ["appreciation", "demand", "rise", "appreciate"], "B2": ["revaluation", "depreciate", "demand", "depreciation"]}}'::jsonb, '{"blanks": {"B1": "appreciation", "B2": "depreciation"}}'::jsonb),
('economics:4-3-exchange-rates:fib:bb7f1037', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'fib', 'fib', 2, '{"question": "Higher UK interest rates relative to overseas tend to make the pound ___B1___, because foreign savers ___B2___ pounds to earn the better return.", "blankOptions": {"B1": ["revaluation", "supply", "appreciate", "depreciate"], "B2": ["appreciation", "demand", "devaluation", "cheaper"]}}'::jsonb, '{"blanks": {"B1": "appreciate", "B2": "demand"}}'::jsonb),
('economics:4-3-exchange-rates:fib:e5f2924b', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'fib', 'fib', 2, '{"question": "A depreciation makes UK exports ___B1___ for foreign buyers but makes imported raw materials ___B2___ for UK firms.", "blankOptions": {"B1": ["cheaper", "revaluation", "demand", "fall"], "B2": ["supply", "more expensive", "rise", "fall"]}}'::jsonb, '{"blanks": {"B1": "cheaper", "B2": "more expensive"}}'::jsonb),
('economics:4-3-exchange-rates:match:fad5ea39', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Exchange rate”?", "options": ["The record of a country''s trade in goods and services, plus income and transfers, with the rest of the world", "A good or service bought from another country, causing an outflow of money", "Comes from overseas buyers of UK exports, foreign investors, and speculators expecting the pound to rise", "The price of one currency expressed in terms of another"]}'::jsonb, '{"answer": 3, "explain": "“Exchange rate” means: The price of one currency expressed in terms of another"}'::jsonb),
('economics:4-3-exchange-rates:match:91a393ee', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Floating exchange rate”?", "options": ["A system where the currency''s value is set purely by demand and supply on foreign exchange markets", "Comes from UK buyers of imports, UK investors abroad, and speculators expecting the pound to fall", "A fall in the value of a currency relative to another", "A good or service sold to another country, causing an inflow of money"]}'::jsonb, '{"answer": 0, "explain": "“Floating exchange rate” means: A system where the currency''s value is set purely by demand and supply on foreign exchange markets"}'::jsonb),
('economics:4-3-exchange-rates:match:01f32852', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Appreciation”?", "options": ["A rise in the value of a currency relative to another", "The price of one currency expressed in terms of another", "A fall in the value of a currency relative to another", "Buying or selling a currency in anticipation of its future value changing"]}'::jsonb, '{"answer": 0, "explain": "“Appreciation” means: A rise in the value of a currency relative to another"}'::jsonb),
('economics:4-3-exchange-rates:match:5a0c22b6', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Depreciation”?", "options": ["A system where the currency''s value is set purely by demand and supply on foreign exchange markets", "A fall in the value of a currency relative to another", "How much the quantity of exports/imports demanded responds to a price change caused by the exchange rate", "A deliberate fall in a currency''s value under a FIXED exchange rate system"]}'::jsonb, '{"answer": 1, "explain": "“Depreciation” means: A fall in the value of a currency relative to another"}'::jsonb),
('economics:4-3-exchange-rates:match:0aecf5e3', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Devaluation”?", "options": ["A rise in the value of a currency relative to another", "A deliberate fall in a currency''s value under a FIXED exchange rate system", "The price of one currency expressed in terms of another", "Buying or selling a currency in anticipation of its future value changing"]}'::jsonb, '{"answer": 1, "explain": "“Devaluation” means: A deliberate fall in a currency''s value under a FIXED exchange rate system"}'::jsonb),
('economics:4-3-exchange-rates:match:bf7fa665', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Revaluation”?", "options": ["A system where the currency''s value is set purely by demand and supply on foreign exchange markets", "Comes from UK buyers of imports, UK investors abroad, and speculators expecting the pound to fall", "A deliberate rise in a currency''s value under a FIXED exchange rate system", "A deliberate fall in a currency''s value under a FIXED exchange rate system"]}'::jsonb, '{"answer": 2, "explain": "“Revaluation” means: A deliberate rise in a currency''s value under a FIXED exchange rate system"}'::jsonb),
